query:
-- Delete order items first
DELETE FROM orderItems WHERE orderId IN (
  SELECT o.id FROM orders o
  LEFT JOIN payments p ON o.id = p.orderId
  WHERE p.status = 'pending' AND o.userId IS NULL
);

-- Delete pending payments
DELETE FROM payments WHERE status = 'pending' AND orderId IN (
  SELECT id FROM orders WHERE userId IS NULL
);

-- Delete the test orders
DELETE FROM orders WHERE userId IS NULL;

